#!/usr/bin/env Rscript

########### ERC visualization script
########### Reads outputs generated by ERC.R and makes:
########### - individual scatter plots
########### - individual bootstrap density plots
########### - combined scatter panels
########### - combined ridge plots for gene groups and OXPHOS complexes

suppressPackageStartupMessages({
  library(dplyr)
  library(readr)
  library(ggplot2)
  library(cowplot)
  library(ggridges)
})

analysis_dir <- "."
out_dir <- file.path(analysis_dir, "erc_output")
fig_dir <- file.path(out_dir, "figures")

if (!dir.exists(fig_dir)) dir.create(fig_dir, recursive = TRUE)

# ----------------------------- #
# Helper functions
# ----------------------------- #

fmt_p <- function(p) {
  ifelse(p < 0.001, "<0.001", sprintf("%.4f", p))
}

clean_group_levels <- function(df) {
  df %>%
    mutate(
      Group = factor(Group, levels = c("50kb", "OL"))
    )
}

make_scatter_plot <- function(plot_df, summary_df, title_text, x_label, y_label) {
  stat_row <- summary_df %>% filter(analysis_name == unique(plot_df$analysis_name)[1])

  plot_df <- clean_group_levels(plot_df)

  ggplot(plot_df, aes(x = x_value, y = y_value, color = Group)) +
    geom_point(size = 3, alpha = 0.7) +
    geom_smooth(data = subset(plot_df, Group == "50kb"),
                method = "lm", se = FALSE, color = "red") +
    geom_smooth(data = subset(plot_df, Group == "OL"),
                method = "lm", se = FALSE, color = "blue") +
    geom_smooth(method = "lm", se = FALSE, color = "black", linetype = "dashed") +
    labs(title = title_text, x = x_label, y = y_label) +
    scale_color_manual(
      values = c("50kb" = "red", "OL" = "blue"),
      labels = c("50kb" = "50-kb Legumes", "OL" = "Other Legumes")
    ) +
    theme_minimal() +
    theme(
      plot.title = element_text(hjust = 0.5, face = "bold"),
      legend.position = "right",
      panel.grid = element_blank(),
      panel.border = element_rect(color = "black", fill = NA)
    ) +
    annotate(
      "text",
      x = min(plot_df$x_value, na.rm = TRUE),
      y = max(plot_df$y_value, na.rm = TRUE),
      label = paste0("r[s] = ", round(stat_row$spearman_rs, 2), "\np = ", fmt_p(stat_row$p_value)),
      hjust = 0,
      vjust = 1,
      size = 5,
      color = "black"
    )
}

make_boot_density_plot <- function(boot_df, summary_df, analysis_name, title_text) {
  stat_row <- summary_df %>% filter(analysis_name == !!analysis_name)
  dat <- boot_df %>% filter(analysis_name == !!analysis_name)

  ggplot(dat, aes(x = bootstrap_rs)) +
    geom_density(fill = "blue", alpha = 0.5) +
    geom_point(aes(x = stat_row$mean_bootstrap_rs, y = 0), size = 4, color = "black") +
    geom_errorbarh(
      aes(xmin = stat_row$ci_low, xmax = stat_row$ci_high, y = 0),
      height = 0.1, color = "black", linewidth = 1
    ) +
    labs(
      title = title_text,
      x = "Bootstrapped Spearman Correlation Coefficients",
      y = "Density"
    ) +
    theme_minimal() +
    theme(
      plot.title = element_text(hjust = 0.5, face = "bold"),
      panel.grid = element_blank(),
      panel.border = element_rect(color = "black", fill = NA)
    )
}

make_ridge_plot <- function(boot_df, summary_df, order_vec, fill_values, x_lab, y_lab) {
  boot_df <- boot_df %>%
    mutate(analysis_name = factor(analysis_name, levels = rev(order_vec)))

  summary_df <- summary_df %>%
    mutate(analysis_name = factor(analysis_name, levels = rev(order_vec)))

  ggplot(boot_df, aes(x = bootstrap_rs, y = analysis_name)) +
    geom_vline(xintercept = 0, linetype = "dashed") +
    geom_density_ridges(aes(fill = analysis_name), alpha = 0.6, scale = 1) +
    geom_errorbarh(
      data = summary_df,
      aes(xmin = ci_low, xmax = ci_high, y = analysis_name),
      height = 0.2, linewidth = 1.2, inherit.aes = FALSE
    ) +
    geom_point(
      data = summary_df,
      aes(x = mean_bootstrap_rs, y = analysis_name),
      size = 4, color = "black", inherit.aes = FALSE
    ) +
    scale_fill_manual(values = fill_values, guide = "none") +
    labs(
      x = x_lab,
      y = y_lab
    ) +
    theme_cowplot() +
    theme(
      legend.position = "none",
      axis.text = element_text(size = 16),
      axis.title = element_text(size = 18)
    ) +
    scale_x_continuous(limits = c(-0.6, 1), breaks = seq(-0.4, 1, by = 0.2))
}

save_plot <- function(plot_obj, filename, width = 8, height = 6) {
  ggsave(file.path(fig_dir, filename), plot_obj, width = width, height = height)
}

# ----------------------------- #
# Read analysis outputs
# ----------------------------- #

complexes_root_plot_data <- read_csv(file.path(out_dir, "complexes_root_plot_data.csv"), show_col_types = FALSE)
complexes_term_plot_data <- read_csv(file.path(out_dir, "complexes_terminal_plot_data.csv"), show_col_types = FALSE)
gene_root_plot_data      <- read_csv(file.path(out_dir, "gene_groups_root_plot_data.csv"), show_col_types = FALSE)
gene_term_plot_data      <- read_csv(file.path(out_dir, "gene_groups_terminal_plot_data.csv"), show_col_types = FALSE)

complexes_root_boot <- read_csv(file.path(out_dir, "complexes_root_bootstrap.csv"), show_col_types = FALSE)
complexes_term_boot <- read_csv(file.path(out_dir, "complexes_terminal_bootstrap.csv"), show_col_types = FALSE)
gene_root_boot      <- read_csv(file.path(out_dir, "gene_groups_root_bootstrap.csv"), show_col_types = FALSE)
gene_term_boot      <- read_csv(file.path(out_dir, "gene_groups_terminal_bootstrap.csv"), show_col_types = FALSE)

load(file.path(out_dir, "erc_results.RData"))

complexes_root_summary <- complexes_root$summary
complexes_term_summary <- complexes_term$summary
gene_root_summary      <- gene_root$summary
gene_term_summary      <- gene_term$summary

# ----------------------------- #
# OXPHOS complex plots
# ----------------------------- #

complex_labels <- c(
  "Complex I" = "Complex I",
  "Complex II" = "Complex II",
  "Complex III" = "Complex III",
  "Complex IV" = "Complex IV",
  "Complex V" = "Complex V"
)

complex_scatter_root <- lapply(names(complex_labels), function(nm) {
  make_scatter_plot(
    plot_df = complexes_root_plot_data %>% filter(analysis_name == nm),
    summary_df = complexes_root_summary,
    title_text = complex_labels[[nm]],
    x_label = "N-mt Branch Length",
    y_label = "mt Branch Length"
  )
})
names(complex_scatter_root) <- names(complex_labels)

complex_scatter_term <- lapply(names(complex_labels), function(nm) {
  make_scatter_plot(
    plot_df = complexes_term_plot_data %>% filter(analysis_name == paste0(nm, " (Terminal)")),
    summary_df = complexes_term_summary,
    title_text = paste0(complex_labels[[nm]], " (Terminal Branches)"),
    x_label = "N-mt Terminal Branch Length",
    y_label = "mt Terminal Branch Length"
  )
})
names(complex_scatter_term) <- names(complex_labels)

complex_boot_root <- lapply(names(complex_labels), function(nm) {
  make_boot_density_plot(
    complexes_root_boot, complexes_root_summary, nm,
    paste0("Distribution of Bootstrapped Correlations (", nm, ")")
  )
})
names(complex_boot_root) <- names(complex_labels)

complex_boot_term <- lapply(names(complex_labels), function(nm) {
  make_boot_density_plot(
    complexes_term_boot, complexes_term_summary, paste0(nm, " (Terminal)"),
    paste0("Distribution of Bootstrapped Correlations (", nm, ", Terminal)")
  )
})
names(complex_boot_term) <- names(complex_labels)

# Save individual complex plots
for (nm in names(complex_scatter_root)) {
  save_plot(complex_scatter_root[[nm]], paste0(gsub(" ", "_", nm), "_scatter_root.pdf"))
  save_plot(complex_boot_root[[nm]], paste0(gsub(" ", "_", nm), "_bootstrap_root.pdf"))
  save_plot(complex_scatter_term[[nm]], paste0(gsub(" ", "_", nm), "_scatter_terminal.pdf"))
  save_plot(complex_boot_term[[nm]], paste0(gsub(" ", "_", nm), "_bootstrap_terminal.pdf"))
}

# Combined OXPHOS scatter panels
legend_complex <- get_legend(complex_scatter_root[["Complex V"]] + theme(legend.position = "right"))
complex_root_nolegend <- lapply(complex_scatter_root, function(p) p + theme(legend.position = "none"))
complex_term_nolegend <- lapply(complex_scatter_term, function(p) p + theme(legend.position = "none"))

combined_scatterplots <- plot_grid(
  complex_root_nolegend[["Complex I"]],
  complex_root_nolegend[["Complex II"]],
  complex_root_nolegend[["Complex III"]],
  complex_root_nolegend[["Complex IV"]],
  complex_root_nolegend[["Complex V"]],
  legend_complex,
  labels = c("A", "B", "C", "D", "E", ""),
  ncol = 2
)

legend_complex_term <- get_legend(complex_scatter_term[["Complex V"]] + theme(legend.position = "right"))
combined_scatterplots_term <- plot_grid(
  complex_term_nolegend[["Complex I"]],
  complex_term_nolegend[["Complex II"]],
  complex_term_nolegend[["Complex III"]],
  complex_term_nolegend[["Complex IV"]],
  complex_term_nolegend[["Complex V"]],
  legend_complex_term,
  labels = c("A", "B", "C", "D", "E", ""),
  ncol = 2
)

save_plot(combined_scatterplots, "combined_scatterplots_oxphos_complexes.pdf", width = 12, height = 14)
save_plot(combined_scatterplots_term, "combined_scatterplots_oxphos_complexes_terminal.pdf", width = 12, height = 14)

# Ridge plot for complexes
complex_order <- c("Complex I", "Complex II", "Complex III", "Complex IV", "Complex V")
OXPHOS_Complexes_ERC <- make_ridge_plot(
  boot_df = complexes_root_boot,
  summary_df = complexes_root_summary,
  order_vec = complex_order,
  fill_values = c(
    "Complex I" = "#666666",
    "Complex II" = "#CC6600",
    "Complex III" = "#9999FF",
    "Complex IV" = "#FF6666",
    "Complex V" = "#66CC99"
  ),
  x_lab = expression(paste("Evolutionary rate correlation strength  ", italic(r[s]))),
  y_lab = "mt N-mt OXPHOS ERC within"
)

save_plot(OXPHOS_Complexes_ERC, "OXPHOS_Complexes_ERC.pdf", width = 10, height = 8)

# ----------------------------- #
# Gene-group plots
# ----------------------------- #

gene_order_root <- c("N-mt OXPHOS", "Cell Cycle", "Glycolysis", "Cyto-ribo", "Plastid")
gene_titles_root <- c(
  "N-mt OXPHOS" = "N-mt OXPHOS",
  "Cell Cycle" = "Cell Cycle",
  "Glycolysis" = "Glycolysis",
  "Cyto-ribo" = "Cyto-ribo",
  "Plastid" = "Plastid"
)

gene_x_labels_root <- c(
  "N-mt OXPHOS" = "N-mt OXPHOS Branch Length",
  "Cell Cycle" = "Cell Cycle Branch Length",
  "Glycolysis" = "Glycolysis Branch Length",
  "Cyto-ribo" = "Cyto-ribo Branch Length",
  "Plastid" = "Plastid Branch Length"
)

gene_x_labels_term <- c(
  "N-mt OXPHOS (Terminal)" = "N-mt OXPHOS Terminal Branch Length",
  "Cell Cycle (Terminal)" = "Cell Cycle Terminal Branch Length",
  "Glycolysis (Terminal)" = "Glycolysis Terminal Branch Length",
  "Cyto-ribo (Terminal)" = "Cyto-ribo Terminal Branch Length",
  "Plastid (Terminal)" = "Plastid Terminal Branch Length"
)

gene_scatter_root <- lapply(gene_order_root, function(nm) {
  make_scatter_plot(
    plot_df = gene_root_plot_data %>% filter(analysis_name == nm),
    summary_df = gene_root_summary,
    title_text = gene_titles_root[[nm]],
    x_label = gene_x_labels_root[[nm]],
    y_label = "mt Branch Length"
  )
})
names(gene_scatter_root) <- gene_order_root

gene_order_term <- c("N-mt OXPHOS (Terminal)", "Cell Cycle (Terminal)", "Glycolysis (Terminal)", "Cyto-ribo (Terminal)", "Plastid (Terminal)")

gene_scatter_term <- lapply(gene_order_term, function(nm) {
  make_scatter_plot(
    plot_df = gene_term_plot_data %>% filter(analysis_name == nm),
    summary_df = gene_term_summary,
    title_text = nm,
    x_label = gene_x_labels_term[[nm]],
    y_label = "mt Terminal Branch Length"
  )
})
names(gene_scatter_term) <- gene_order_term

gene_boot_root <- lapply(gene_order_root, function(nm) {
  make_boot_density_plot(
    gene_root_boot, gene_root_summary, nm,
    paste0("Distribution of Bootstrapped Correlations (", nm, ")")
  )
})
names(gene_boot_root) <- gene_order_root

gene_boot_term <- lapply(gene_order_term, function(nm) {
  make_boot_density_plot(
    gene_term_boot, gene_term_summary, nm,
    paste0("Distribution of Bootstrapped Correlations (", nm, ")")
  )
})
names(gene_boot_term) <- gene_order_term

for (nm in gene_order_root) {
  base_nm <- gsub("[^A-Za-z0-9]+", "_", nm)
  save_plot(gene_scatter_root[[nm]], paste0(base_nm, "_scatter_root.pdf"))
  save_plot(gene_boot_root[[nm]], paste0(base_nm, "_bootstrap_root.pdf"))
}

for (nm in gene_order_term) {
  base_nm <- gsub("[^A-Za-z0-9]+", "_", nm)
  save_plot(gene_scatter_term[[nm]], paste0(base_nm, "_scatter_terminal.pdf"))
  save_plot(gene_boot_term[[nm]], paste0(base_nm, "_bootstrap_terminal.pdf"))
}

legend_gene <- get_legend(gene_scatter_root[["Plastid"]] + theme(legend.position = "right"))
gene_root_nolegend <- lapply(gene_scatter_root, function(p) p + theme(legend.position = "none"))
gene_term_nolegend <- lapply(gene_scatter_term, function(p) p + theme(legend.position = "none"))

combined_scatterplots_gene_groups <- plot_grid(
  gene_root_nolegend[["N-mt OXPHOS"]],
  gene_root_nolegend[["Cell Cycle"]],
  gene_root_nolegend[["Glycolysis"]],
  gene_root_nolegend[["Cyto-ribo"]],
  gene_root_nolegend[["Plastid"]],
  legend_gene,
  labels = c("A", "B", "C", "D", "E", ""),
  ncol = 2
)

legend_gene_term <- get_legend(gene_scatter_term[["Plastid (Terminal)"]] + theme(legend.position = "right"))
combined_scatterplots_gene_groups_term <- plot_grid(
  gene_term_nolegend[["N-mt OXPHOS (Terminal)"]],
  gene_term_nolegend[["Cell Cycle (Terminal)"]],
  gene_term_nolegend[["Glycolysis (Terminal)"]],
  gene_term_nolegend[["Cyto-ribo (Terminal)"]],
  gene_term_nolegend[["Plastid (Terminal)"]],
  legend_gene_term,
  labels = c("A", "B", "C", "D", "E", ""),
  ncol = 2
)

save_plot(combined_scatterplots_gene_groups, "combined_scatterplots_gene_groups.pdf", width = 12, height = 14)
save_plot(combined_scatterplots_gene_groups_term, "combined_scatterplots_gene_groups_terminal.pdf", width = 12, height = 14)

Gene_Groups_ERC <- make_ridge_plot(
  boot_df = gene_root_boot,
  summary_df = gene_root_summary,
  order_vec = c("N-mt OXPHOS", "Glycolysis", "Cell Cycle", "Cyto-ribo", "Plastid"),
  fill_values = c(
    "N-mt OXPHOS" = "#666666",
    "Glycolysis" = "#CC6600",
    "Cell Cycle" = "#9999FF",
    "Cyto-ribo" = "#FF6666",
    "Plastid" = "#66CC99"
  ),
  x_lab = expression(paste("Evolutionary rate correlation strength  ", italic(r[s]))),
  y_lab = "ERC between mt and"
)

save_plot(Gene_Groups_ERC, "Gene_Groups_ERC.pdf", width = 10, height = 8)

combined_figure <- plot_grid(
  Gene_Groups_ERC +
    theme(plot.margin = margin(t = 10, r = 20, b = 30, l = 10)),
  OXPHOS_Complexes_ERC +
    theme(plot.margin = margin(t = 10, r = 10, b = 30, l = 20)),
  labels = c("A", "B"),
  ncol = 2,
  align = "h",
  rel_widths = c(1, 1)
)

save_plot(combined_figure, "combined_figure_ERC.pdf", width = 15, height = 10)

message("Visualization complete.")
message("Figures written to: ", normalizePath(fig_dir))
